#include <stdio.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N; scanf("%lld", &N);
        long long cars = (N + 3) / 4;
        printf("%lld\n", cars);
    }
    return 0;
}

